#include<bits/stdc++.h>
using namespace std;
const __int128 mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        long long N,M;
        scanf("%lld%lld",&N,&M);
        __int128 l=1,r=N,best=1,n=N,m=M;
        while(l<=r)
        {
            __int128 mid=(l+r)/2;
            if((__int128)((mid*mid-mid)/2+1)<=m)
            {
                best=mid;
                l=mid+1;
            }
            else
            {
                r=mid-1;
            }
        }
        __int128 x=best;
        __int128 ans=((x-1)*(x+1)*x/6+x)+((m*2-n+x+2)*(n-x-1)/2);
        ans%=mod;
        printf("%lld\n",(long long)(ans));
    }
    return 0;
}
